mapper.select:
select uc.id, uc.user_id userId, uc.pay_type payType, uc.pay_usage_id payUsageId, uc.amount, uc.bill_type billType, uc.pay_time payTime, uc.create_time createTime, uc.remark, su.name from user_cost uc left join sys_user su on su.id = uc.user_id where 1=1
and uc.pay_type = #{dto.payType}
and uc.pay_usage_id = #{dto.payUsageId}
and uc.bill_type = #{dto.billType}
